// === ViraSEO Advanced Page Inspector ===
// Full SEO audit of a competitor page — extracts everything useful for SEO espionage.

const html = $input.first().json.body || '';
const url = $('Webhook').first().json.body.url || '';
const keyword = ($('Webhook').first().json.body.keyword || '').toLowerCase().trim();
const statusCode = $input.first().json.statusCode || 200;
const responseTime = $input.first().json.timings ? $input.first().json.timings.total : 0;

// Helper: strip tags
function stripTags(s) { return (s||'').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim(); }

// === TITLE ===
let title = '';
const titleMatch = html.match(/<title[^>]*>(.*?)<\/title>/si);
if (titleMatch) title = stripTags(titleMatch[1]);

// === META DESCRIPTION ===
let metaDesc = '';
let m = html.match(/<meta[^>]+name\s*=\s*["']description["'][^>]*content\s*=\s*["']([^"']*)["']/i);
if (m) metaDesc = m[1];
if (!m) { m = html.match(/<meta[^>]+content\s*=\s*["']([^"']*)["'][^>]*name\s*=\s*["']description["']/i); if (m) metaDesc = m[1]; }

// === OG TAGS ===
let ogTitle = ''; let ogDesc = ''; let ogImage = '';
m = html.match(/<meta[^>]+property\s*=\s*["']og:title["'][^>]*content\s*=\s*["']([^"']*)["']/i);
if (m) ogTitle = m[1];
m = html.match(/<meta[^>]+property\s*=\s*["']og:description["'][^>]*content\s*=\s*["']([^"']*)["']/i);
if (m) ogDesc = m[1];
m = html.match(/<meta[^>]+property\s*=\s*["']og:image["'][^>]*content\s*=\s*["']([^"']*)["']/i);
if (m) ogImage = m[1];

// === CANONICAL ===
let canonical = '';
m = html.match(/<link[^>]+rel\s*=\s*["']canonical["'][^>]*href\s*=\s*["']([^"']+)["']/i);
if (m) canonical = m[1];

// === ROBOTS ===
let robots = 'index, follow';
m = html.match(/<meta[^>]+name\s*=\s*["']robots["'][^>]*content\s*=\s*["']([^"']*)["']/i);
if (m) robots = m[1];

// === SCHEMA TYPES ===
const schemaTypes = [...new Set((html.match(/"@type"\s*:\s*"([^"]+)"/gi) || []).map(s => s.match(/"([^"]+)"$/)[1]))];

// === CONTENT EXTRACTION (remove scripts/styles/nav/footer) ===
let content = html.replace(/<(script|style|svg|template|iframe|noscript)[^>]*>[\s\S]*?<\/\1>/gi, ' ');
let body = content;
const bodyMatch = content.match(/<body[^>]*>([\s\S]*)<\/body>/i);
if (bodyMatch) body = bodyMatch[1];
body = body.replace(/<(nav|footer|header|aside|form)[^>]*>[\s\S]*?<\/\1>/gi, ' ');

// Try main/article first
let mainContent = '';
let mm2 = body.match(/<main[^>]*>([\s\S]*?)<\/main>/i);
if (mm2) mainContent = mm2[1];
if (!mainContent) { mm2 = body.match(/<article[^>]*>([\s\S]*?)<\/article>/i); if (mm2) mainContent = mm2[1]; }
if (!mainContent) { mm2 = body.match(/<div[^>]*class\s*=\s*["'][^"']*entry-content[^"']*["'][^>]*>([\s\S]*?)<\/div>/i); if (mm2) mainContent = mm2[1]; }
if (!mainContent) mainContent = body;

const text = stripTags(mainContent);
const words = text.split(/\s+/).filter(w => w.length > 0);
const wordCount = words.length;

// === HEADINGS ===
const h1Matches = html.match(/<h1[^>]*>(.*?)<\/h1>/gi) || [];
const h2Matches = html.match(/<h2[^>]*>(.*?)<\/h2>/gi) || [];
const h3Matches = html.match(/<h3[^>]*>(.*?)<\/h3>/gi) || [];
const h1Texts = h1Matches.map(h => stripTags(h)).filter(t => t.length > 0);
const h2Texts = h2Matches.map(h => stripTags(h)).filter(t => t.length > 0);
const h3Texts = h3Matches.map(h => stripTags(h)).filter(t => t.length > 0);

// === IMAGES ===
const imgMatches = html.match(/<img\b[^>]*>/gi) || [];
const imagesCount = imgMatches.length;
let imagesNoAlt = 0;
imgMatches.forEach(tag => { if (!/\balt\s*=\s*["'][^"']+["']/i.test(tag)) imagesNoAlt++; });

// === LINKS ===
const host = new URL(url).hostname;
const linkMatches = html.match(/<a\s[^>]*href\s*=\s*["']([^"'#]+)["'][^>]*>/gi) || [];
let internalLinks = 0; let externalLinks = 0;
linkMatches.forEach(l => {
  const hrefM = l.match(/href\s*=\s*["']([^"'#]+)["']/i);
  if (!hrefM) return;
  const href = hrefM[1];
  if (href.startsWith('/') || href.includes(host)) internalLinks++;
  else if (href.startsWith('http')) externalLinks++;
});

// === PARAGRAPHS ===
const paragraphs = (html.match(/<p\b[^>]*>/gi) || []).length;

// === TABLES / VIDEOS / FAQ ===
const tables = (html.match(/<table\b/gi) || []).length;
const videos = (html.match(/<(video|iframe)[^>]*(youtube|vimeo|aparat|mp4)/gi) || []).length;
const hasFaq = /سوالات متداول|پرسش.*متداول|FAQ|faq-section|schema.*FAQPage/i.test(html);

// === TOP KEYWORDS (TF) ===
const stops = ['و','در','به','از','که','این','را','با','است','برای','آن','یک','تا','هم','ها','یا','شده','می','بر','اما','هر','نیز','the','is','a','an','of','to','in','for','on','with','by','that','this'];
const wordList = text.toLowerCase().split(/[\s\u200C\u200B,.;:!?\-\(\)\[\]\/\\]+/).filter(w => w.length > 2 && !stops.includes(w) && !/^\d+$/.test(w));
const freq = {}; wordList.forEach(w => freq[w] = (freq[w]||0) + 1);
const topKeywords = Object.entries(freq).sort((a,b) => b[1]-a[1]).slice(0,10).map(([word,count]) => ({word, count}));

// === KEYWORD ANALYSIS ===
let kwAnalysis = {};
if (keyword) {
  const kwLower = keyword.toLowerCase();
  const titleLower = title.toLowerCase();
  const metaLower = metaDesc.toLowerCase();
  const urlLower = url.toLowerCase();
  const inTitle = titleLower.includes(kwLower) ? 1 : 0;
  const inH1 = h1Texts.some(h => h.toLowerCase().includes(kwLower)) ? 1 : 0;
  const inH2 = h2Texts.some(h => h.toLowerCase().includes(kwLower)) ? 1 : 0;
  const inMeta = metaLower.includes(kwLower) ? 1 : 0;
  const inUrl = urlLower.includes(kwLower) ? 1 : 0;
  const kwCount = (text.toLowerCase().split(kwLower).length - 1);
  const density = wordCount > 0 ? Math.round((kwCount / wordCount) * 10000) / 100 : 0;
  const prominence = Math.min(100, (inTitle?25:0) + (inH1?20:0) + (inH2?10:0) + (inMeta?15:0) + (inUrl?15:0) + Math.min(15, Math.round(density*5)));
  kwAnalysis = { in_title: inTitle, in_h1: inH1, in_h2: inH2, in_meta: inMeta, in_url: inUrl, density, prominence, count: kwCount };
}

// === READING LEVEL (sentence length based) ===
const sentences = text.split(/[.!?؟۔]+/).filter(s => s.trim().length > 10);
const avgSentenceLen = sentences.length > 0 ? Math.round(words.length / sentences.length) : 0;
const readingLevel = avgSentenceLen; // lower = easier

// === CONTENT TYPE DETECTION ===
let contentType = '-';
if (/product|shop|store|cart|add-to-cart|woocommerce/i.test(url) || /"@type"\s*:\s*"Product"/i.test(html)) contentType = 'product';
else if (/blog|article|mag|news|post|wiki/i.test(url) || /"@type"\s*:\s*"(Article|BlogPosting)"/i.test(html)) contentType = 'article';
else if (/service|khadamat/i.test(url)) contentType = 'service';
else if (wordCount > 300) contentType = 'article';

// === SEO STRENGTHS & WEAKNESSES ===
const strengths = [];
const weaknesses = [];

if (wordCount >= 1500) strengths.push('محتوای طولانی و جامع (' + wordCount + ' کلمه)');
else if (wordCount >= 800) strengths.push('طول محتوا مناسب (' + wordCount + ' کلمه)');
else weaknesses.push('محتوا کوتاه است (' + wordCount + ' کلمه). رقبای قوی معمولاً ۱۵۰۰+ کلمه دارند.');

if (h2Texts.length >= 3) strengths.push('ساختار هدینگ خوب (' + h2Texts.length + ' زیرعنوان H2)');
else weaknesses.push('تعداد هدینگ H2 کم است (' + h2Texts.length + '). ساختارمندی محتوا ضعیف.');

if (imagesCount >= 3) strengths.push('استفاده خوب از تصاویر (' + imagesCount + ' عدد)');
else weaknesses.push('تصاویر کم (' + imagesCount + '). محتوای بصری ضعیف.');

if (imagesNoAlt > 0) weaknesses.push(imagesNoAlt + ' تصویر بدون alt text (مشکل دسترسی‌پذیری و سئو).');

if (tables > 0) strengths.push('استفاده از جدول (' + tables + ' عدد). محتوای ساختاریافته.');
if (hasFaq) strengths.push('بخش FAQ/سوالات متداول دارد (شانس Featured Snippet).');
else weaknesses.push('بخش FAQ ندارد. فرصت Featured Snippet از دست رفته.');

if (videos > 0) strengths.push('ویدیو دارد (' + videos + ' عدد). جذابیت و زمان ماندگاری بالا.');

if (internalLinks >= 5) strengths.push('لینک‌سازی داخلی قوی (' + internalLinks + ' لینک)');
else weaknesses.push('لینک داخلی کم (' + internalLinks + '). ساختار سیلو ضعیف.');

if (externalLinks >= 1 && externalLinks <= 5) strengths.push('استناد مناسب به منابع خارجی (' + externalLinks + ' لینک)');
else if (externalLinks === 0) weaknesses.push('هیچ لینک خارجی/استنادی ندارد.');
else if (externalLinks > 10) weaknesses.push('لینک خارجی زیاد (' + externalLinks + '). ممکن است link juice زیادی خارج شود.');

if (schemaTypes.length > 0) strengths.push('داده ساختاریافته (Schema): ' + schemaTypes.join(', '));
else weaknesses.push('هیچ Schema/JSON-LD ندارد. فرصت Rich Snippet از دست رفته.');

if (metaDesc && metaDesc.length >= 120 && metaDesc.length <= 160) strengths.push('طول متا دسکریپشن بهینه (' + metaDesc.length + ' کاراکتر)');
else if (!metaDesc) weaknesses.push('متا دسکریپشن ندارد!');
else if (metaDesc.length < 100) weaknesses.push('متا دسکریپشن کوتاه (' + metaDesc.length + ' کاراکتر). باید ۱۲۰-۱۶۰ باشد.');

if (title.length >= 30 && title.length <= 65) strengths.push('طول عنوان بهینه (' + title.length + ' کاراکتر)');
else if (title.length > 65) weaknesses.push('عنوان بلند (' + title.length + ' کاراکتر). گوگل آن را کوتاه می‌کند.');
else if (title.length < 30) weaknesses.push('عنوان کوتاه (' + title.length + ' کاراکتر).');

if (keyword) {
  if (kwAnalysis.in_title) strengths.push('کلمه کلیدی در عنوان وجود دارد.');
  else weaknesses.push('کلمه کلیدی در عنوان نیست!');
  if (kwAnalysis.in_h1) strengths.push('کلمه کلیدی در H1 استفاده شده.');
  else weaknesses.push('کلمه کلیدی در H1 نیست.');
  if (kwAnalysis.density >= 0.5 && kwAnalysis.density <= 2.5) strengths.push('تراکم کلمه کلیدی مناسب (' + kwAnalysis.density + '٪)');
  else if (kwAnalysis.density < 0.5) weaknesses.push('تراکم کلمه کلیدی خیلی کم (' + kwAnalysis.density + '٪)');
  else weaknesses.push('تراکم کلمه کلیدی زیاد (' + kwAnalysis.density + '٪). خطر keyword stuffing.');
}

// === FINAL SCORE ===
let score = 0;
score += Math.min(30, Math.round(wordCount / 50)); // up to 30 for 1500 words
score += Math.min(15, h2Texts.length * 3);
score += Math.min(10, imagesCount * 2);
score += (h1Texts.length >= 1) ? 10 : 0;
score += (tables > 0) ? 5 : 0;
score += (hasFaq) ? 10 : 0;
score += (schemaTypes.length > 0) ? 10 : 0;
score += (externalLinks >= 1) ? 5 : 0;
score += (metaDesc.length >= 100) ? 5 : 0;
score = Math.min(100, score);

return [{
  json: {
    url, word_count: wordCount, h1: h1Texts.length, h2: h2Texts.length, h3: h3Texts.length,
    h1_texts: h1Texts.slice(0,3), h2_texts: h2Texts.slice(0,12), h3_texts: h3Texts.slice(0,5),
    images: imagesCount, images_no_alt: imagesNoAlt,
    internal_links: internalLinks, external_links: externalLinks,
    title, meta_desc: metaDesc, og_title: ogTitle, og_description: ogDesc, og_image: ogImage,
    canonical_url: canonical, robots_meta: robots,
    schema: schemaTypes, paragraphs, tables, videos,
    has_faq: hasFaq ? 1 : 0, has_video: videos > 0 ? 1 : 0, has_table: tables > 0 ? 1 : 0,
    content_type: contentType, reading_level: readingLevel,
    keyword_density: kwAnalysis.density || 0,
    top_keywords: topKeywords, word_count_score: score,
    keyword_analysis: kwAnalysis,
    response_time: responseTime,
    strengths, weaknesses,
    section_words: h2Texts.slice(0,8).map(h => ({heading: h, words: '—'}))
  }
}];
